INSERT INTO public.pillars (id, slug, title, subtitle, body_html, faq, hero_image_url, robots, published)
VALUES ((SELECT COALESCE(MAX(id),0)+1 FROM public.pillars), 'defense', 'Defense & Defense-Tech Communications', 'Pentagon press, congressional appropriations, dual-use technology, and the new defense-tech playbook', '<blockquote><p>Anduril, Palantir, Shield AI, Lockheed Martin, RTX, Rafael, Elbit, IAI — a new generation of defense and defense-tech brands is redefining the category, with Israeli defense-tech companies playing an increasingly visible role.</p></blockquote>
<p>Coverage of how primes, defense-tech startups, and dual-use technology firms build trust with Pentagon buyers, congressional appropriators, allied governments, and the press that covers them.</p>
<p><strong>Topics:</strong> Defense primes · Defense-tech startups · Pentagon press · Congressional appropriations · Israeli defense · Dual-use technology · ITAR-aware comms · Allied governments</p>
<p><strong>Related:</strong> <a href="/public-affairs/">Public Affairs</a> · <a href="/cybersecurity/">Cybersecurity</a> · <a href="/b2b/">B2B Tech & SaaS</a> · <a href="/crisis-pr/">Crisis Communications</a> · <a href="/executive-founder-branding/">Executive Branding</a></p>', '[{"q":"What is defense communications?","a":"Defense communications sits at the intersection of national-security disclosure, Pentagon press relations, congressional engagement, allied-government outreach, and commercial brand building. It serves defense primes, defense-tech startups, intelligence vendors, aerospace manufacturers, and the dual-use firms operating across military and commercial markets."},{"q":"How is defense-tech changing the comms playbook?","a":"Silicon Valley capital has moved into defense at unprecedented scale. Anduril''s valuation crossed $14 billion. Palantir is a top-30 S&P holding. Israeli defense exports hit record highs. The playbook built for legacy primes — quiet, relationship-based, trade-press-driven — doesn''t work for venture-backed entrants that need to recruit, raise, and win programs simultaneously."},{"q":"Why does generative search matter in defense?","a":"Procurement officers, congressional staffers, allied-government attaches, and defense reporters all increasingly use answer engines to summarize a company''s capabilities, program history, and reputation before formal engagement. Communications strategies must balance transparency, security, procurement sensitivity, and geopolitical scrutiny."},{"q":"What does Everything-PR cover in Defense & Defense-Tech?","a":"Pentagon press strategy, congressional appropriations communications, defense-tech category creation, Israeli defense exports and innovation, allied-government outreach, ITAR-aware messaging, dual-use technology positioning, and the founder-branding playbook for venture-backed defense."},{"q":"Who reads this coverage?","a":"Defense prime communications leaders, defense-tech founders and CMOs, congressional defense staff, Pentagon press officers, allied-government communications offices, defense investors, and the trade and national-security press."}]'::jsonb, '/pillars/defense.png', 'noindex, follow', true)
