INSERT INTO public.categories (id, slug, name, description, seo_title, seo_description) VALUES ((SELECT COALESCE(MAX(id),0)+1 FROM public.categories), 'defense', 'Defense & Defense-Tech', 'Pentagon press, congressional appropriations, dual-use technology, and the new defense-tech playbook', 'Defense & Defense-Tech Communications — Everything-PR', 'Coverage of defense primes, defense-tech startups, dual-use technology, and the global ecosystem reshaping how military, intelligence, and security brands build credibility with Pentagon buyers, allied governments, and the press.') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, seo_title=EXCLUDED.seo_title, seo_description=EXCLUDED.seo_description, updated_at=now();

INSERT INTO public.pillars (id, slug, title, subtitle, body_html, faq, hero_image_url, robots, published)
VALUES ((SELECT COALESCE(MAX(id),0)+1 FROM public.pillars), 'luxury', 'Luxury Communications', 'UHNW audience reach, editorial validation, and AI-assisted research at the top of the luxury funnel', '<blockquote><p>Luxury commerce runs on scarcity, narrative, and authority.</p></blockquote>
<p>Many UHNW buyers now begin with private networks, editorial validation, and increasingly, AI-assisted research. Coverage of how luxury brands, private banks, watchmakers, jewelers, private aviation operators, hospitality groups, and luxury real estate firms build authority across the gatekeepers — old and new — who shape what the wealthy decide.</p>
<p><strong>Topics:</strong> Luxury fashion · Watches · Jewelry · Private aviation · Yachts · Hospitality · Luxury real estate · UHNW · Family offices · Wealth migration</p>
<p><strong>Related:</strong> <a href="/real-estate/">Real Estate & PropTech</a> · <a href="/travel/">Travel & Hospitality</a> · <a href="/beauty/">Beauty</a> · <a href="/executive-founder-branding/">Executive Branding</a> · <a href="/ai/">AI Communications</a></p>', '[{"q":"What is luxury communications?","a":"Luxury communications builds brand authority and manages reputation for luxury fashion, jewelry, watches, hospitality, private aviation, yachts, automotive, real estate, spirits, and the private-banking and wealth-management firms serving UHNW clients. It blends editorial placement, generative search visibility, event strategy, founder positioning, and gated-channel marketing."},{"q":"How is UHNW buyer research changing?","a":"An estimated 142,000 high-net-worth individuals changed countries in 2025 — the largest single-year movement of private capital on record. That migration is mediated by AI-assisted research, private-banker referrals, and a luxury editorial ecosystem — Robb Report, Mansion Global, Financial Times How to Spend It, Haute Living, Town & Country — whose editorial influence increasingly shapes AI-generated recommendations."},{"q":"Why does generative search matter for luxury brands?","a":"The brands cited inside answer engines for &quot;best private aviation operator,&quot; &quot;top family office in Geneva,&quot; &quot;most collectible independent watchmaker&quot; are the brands that win the inquiry. The brands absent from those answers lose the consideration set before the first call — quietly, without ever knowing."},{"q":"What does Everything-PR cover in Luxury?","a":"Luxury fashion and jewelry strategy, watches, private aviation, yachts, automotive, hospitality, luxury real estate, UHNW audience reach, AI visibility for luxury brands, wealth migration coverage, family-office communications, and original research — including The Wealth Migration Report™ and The Luxury AI Authority Index™."},{"q":"Who reads this coverage?","a":"Luxury brand CMOs, private bank communications leaders, family-office principals, hospitality and aviation marketing leaders, luxury real estate brokerages, and the editorial gatekeepers across the global wealth media ecosystem."}]'::jsonb, '/pillars/luxury.png', 'noindex, follow', true)
