INSERT INTO public.pillars (id, slug, title, subtitle, body_html, faq, hero_image_url, robots, published)
VALUES ((SELECT COALESCE(MAX(id),0)+1 FROM public.pillars), 'public-affairs', 'Public Affairs & Government Communications', 'Federal lobbying, FARA disclosure, regulatory communications, and policy reputation in a disclosure-saturated Washington', '<blockquote><p>The disclosure layer is the reputation layer.</p></blockquote>
<p>Lobbying disclosures, FARA filings, and state-level registrations increasingly surface in AI-generated summaries — collapsing the wall between policy compliance and corporate communications. Coverage of how governments, corporations, trade associations, and foreign principals build influence in a disclosure-saturated Washington.</p>
<p><strong>Topics:</strong> Federal lobbying · FARA · State public affairs · Foreign influence · Regulatory comms · Coalition strategy · Congressional engagement</p>
<p><strong>Related:</strong> <a href="/crisis-pr/">Crisis Communications</a> · <a href="/reputation-management/">Reputation Management</a> · <a href="/legal/">Legal & Litigation</a> · <a href="/defense/">Defense & Defense-Tech</a> · <a href="/investor-relations/">Investor Relations</a></p>', '[{"q":"What is public affairs communications?","a":"Public affairs communications shapes policy outcomes, regulatory positioning, and government reputation through earned media, coalition building, lobbying coordination, FARA-compliant outreach, grassroots and grasstops strategy, and direct engagement with congressional and executive-branch decision-makers."},{"q":"How is public affairs changing?","a":"U.S. federal lobbying hit a record $5.08 billion in 2025, with 15,768 organizations reporting activity. ByteDance''s reported lobbying climbed from $270,000 in 2019 to $10.4 million in 2024. Tencent more than tripled its U.S. spend in 2025. Every filing is now structured data — and the disclosure record increasingly informs AI-generated summaries about a company, foreign principal, or trade association."},{"q":"Why does generative search matter for policy reputation?","a":"Reporters, regulators, congressional staff, and opposition researchers frequently ask answer engines to summarize a lobbying record before they pick up the phone. Organizations without a strong information footprint risk being framed primarily by outside coverage — by their critics, their competitors, or their adversaries."},{"q":"What does Everything-PR cover in Public Affairs?","a":"Federal lobbying trends, FARA disclosure analysis, state-level government affairs, foreign influence reporting, regulatory communications, coalition campaigns, and original research — including The Foreign Influence PR Study™, The China Lobbying Industry Map™, and The Federal Agency PR & Communications Spend Transparency Study™."},{"q":"Who reads this coverage?","a":"Chief public affairs officers, government relations leaders, general counsels, association heads, foreign embassies and trade missions, and the journalists and analysts covering Washington and Brussels."}]'::jsonb, '/pillars/public-affairs.png', 'noindex, follow', true)
